import{_ as t,c as e,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"プラットフォーム機能: プランレビューとコードレビュー | Plannotator","description":"Plannotatorのプラットフォーム機能を学びます。プランレビューとコードレビューを含み、可視化レビュー、アノテーション追加、画像マークアップなどのコアスキルを習得します。","frontmatter":{"title":"プラットフォーム機能: プランレビューとコードレビュー | Plannotator","sidebarTitle":"AIプランとコードのレビュー","subtitle":"プラットフォーム機能: プランレビューとコードレビュー","description":"Plannotatorのプラットフォーム機能を学びます。プランレビューとコードレビューを含み、可視化レビュー、アノテーション追加、画像マークアップなどのコアスキルを習得します。","order":2},"headers":[],"relativePath":"ja/backnotprop/plannotator/platforms/index.md","filePath":"ja/backnotprop/plannotator/platforms/index.md"}'),i={name:"ja/backnotprop/plannotator/platforms/index.md"};function n(l,a,d,s,h,c){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="プラットフォーム機能" tabindex="-1">プラットフォーム機能 <a class="header-anchor" href="#プラットフォーム機能" aria-label="Permalink to &quot;プラットフォーム機能&quot;">​</a></h1><p>この章では、Plannotatorの2つのコア機能である<strong>プランレビュー</strong>と<strong>コードレビュー</strong>を紹介します。AIが生成したプランを可視化してレビューする方法、各種アノテーションの追加、画像マークアップの添付、そしてgit diffコード変更のレビュー方法を学びます。</p><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前にご確認ください</p><p>この章を学習する前に、以下の準備が完了していることを確認してください：</p><ul><li>✅ <a href="./../start/getting-started/">クイックスタート</a>チュートリアルを完了済み</li><li>✅ Plannotatorプラグインをインストール済み（<a href="./../start/installation-claude-code/">Claude Code</a>または<a href="./../start/installation-opencode/">OpenCode</a>）</li></ul></div><h2 id="この章の内容" tabindex="-1">この章の内容 <a class="header-anchor" href="#この章の内容" aria-label="Permalink to &quot;この章の内容&quot;">​</a></h2><h3 id="プランレビュー" tabindex="-1">プランレビュー <a class="header-anchor" href="#プランレビュー" aria-label="Permalink to &quot;プランレビュー&quot;">​</a></h3><p>AIが生成した実行プランをレビューし、修正提案を追加して、AIをあなたの意図通りに動作させる方法を学びます。</p><table tabindex="0"><thead><tr><th>チュートリアル</th><th>説明</th></tr></thead><tbody><tr><td><a href="./plan-review-basics/">プランレビューの基本</a></td><td>Plannotatorを使用してAIが生成したプランを可視化レビューする方法を学びます。プランの承認または却下を含みます</td></tr><tr><td><a href="./plan-review-annotations/">プランアノテーションの追加</a></td><td>プランに異なるタイプのアノテーション（削除、置換、挿入、コメント）を追加する方法を習得します</td></tr><tr><td><a href="./plan-review-images/">画像マークアップの追加</a></td><td>プランレビューに画像を添付し、ブラシ、矢印、円形ツールでマークアップする方法を学びます</td></tr></tbody></table><h3 id="コードレビュー" tabindex="-1">コードレビュー <a class="header-anchor" href="#コードレビュー" aria-label="Permalink to &quot;コードレビュー&quot;">​</a></h3><p>コード変更をレビューし、行レベルのアノテーションを追加して、コミット前に問題を発見する方法を学びます。</p><table tabindex="0"><thead><tr><th>チュートリアル</th><th>説明</th></tr></thead><tbody><tr><td>---</td><td>---</td></tr><tr><td><a href="./code-review-annotations/">コードアノテーションの追加</a></td><td>コードレビューで行レベルのアノテーション（comment/suggestion/concern）を追加する方法を習得します</td></tr><tr><td><a href="./code-review-diff-types/">Diffビューの切り替え</a></td><td>コードレビューで異なるdiffタイプ（uncommitted/staged/last commit/branch）を切り替える方法を学びます</td></tr></tbody></table><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">推奨学習順序</p><p>使用シナリオに応じて、適切な学習パスを選択してください：</p><p><strong>パスA：プランレビュー優先</strong>（初心者におすすめ）</p><ol><li><a href="./plan-review-basics/">プランレビューの基本</a> → まず基本的なプランレビューフローを学ぶ</li><li><a href="./plan-review-annotations/">プランアノテーションの追加</a> → プランを正確に修正する方法を学ぶ</li><li><a href="./plan-review-images/">画像マークアップの追加</a> → 画像でより明確に意図を伝える</li><li>その後、コードレビューシリーズを学習</li></ol><p><strong>パスB：コードレビュー優先</strong>（Code Review経験のある開発者向け）</p><ol><li><a href="./code-review-basics/">コードレビューの基本</a> → コードレビュー画面に慣れる</li><li><a href="./code-review-annotations/">コードアノテーションの追加</a> → 行レベルアノテーションを学ぶ</li><li><a href="./code-review-diff-types/">Diffビューの切り替え</a> → 異なるdiffタイプを習得</li><li>その後、プランレビューシリーズを学習</li></ol></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>この章を完了したら、以下の学習を続けることができます：</p><ul><li><a href="./../advanced/url-sharing/">URL共有</a> - URLでプランとアノテーションを共有し、チームコラボレーションを実現</li><li><a href="./../advanced/obsidian-integration/">Obsidian連携</a> - 承認したプランをObsidianに自動保存</li><li><a href="./../advanced/remote-mode/">リモートモード</a> - SSH、devcontainer、WSL環境でPlannotatorを使用</li></ul>',16)])])}const b=t(i,[["render",n]]);export{f as __pageData,b as default};
